import{_ as i,b as o,a as u,c as n,d as s}from"./Pagetitle.vue_vue_type_script_setup_true_lang-19a8f794.js";import{_ as a}from"./QuestionTemp4.vue_vue_type_script_setup_true_lang-0635940e.js";import{_ as c}from"./SeihoTestLayout-6c2c3d5f.js";import{o as y,a as v,w as r,b as p,d as e}from"./app-48c62074.js";import"./AdSenseUnit.vue_vue_type_script_setup_true_lang-14442cde.js";const k={class:"bg-gray-100 text-gray-800 py-10"},b={class:"max-w-4xl mx-auto mt-4 space-y-2"},t="生命保険計理",l="2021年度 フォームB",w={__name:"Keiri2021b",setup(T){return(m,f)=>(y(),v(c,{title:t},{default:r(()=>[p("section",k,[e(i,{title:t,description:l}),p("div",b,[e(a,{questionNumber:1,title:t,subject:l,contents:[{answer:"2,710",questionTitle:"複利計算",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"複利では、元金に利息が組み込まれながら増えていく。まず6か月後の元利合計を求め、そこから元金を差し引いて利息を求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["元利合計 = 元金 × (1 + 利率)<sup>運用期間</sup>","利息 = 元利合計 − 元金"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["元金：300,000円","月利：0.15％ = 0.0015","運用期間：6か月"]},{type:"text",value:"① 元利合計"},{type:"formulaBlock",value:["= 300,000円 × (1 + 0.0015)<sup>6</sup>","= 300,000円 × 1.0090338","= 302,710.14円"]},{type:"text",value:"② 利息"},{type:"formulaBlock",value:["= 302,710.14円 − 300,000円","= 2,710.14円"]},{type:"result",value:"▶ 答え 2,710円（円未満四捨五入）"}]},{answer:"310,963",questionTitle:"複利計算（半年複利）",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"年利1.2％で半年複利の場合、半年ごとに0.6％ずつ増える。3年間では半年が6回あるため、半年利率で6回複利計算する。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["元利合計 = 元金 × (1 + 期間利率)<sup>複利回数</sup>"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["元金：300,000円","年利：1.2％","半年利率：= 1.2％ ÷ 2 = 0.6％ = 0.006","複利回数：= 3年 × 年2回 = 6回"]},{type:"formulaBlock",value:["元利合計","= 300,000円 × (1 + 0.006)<sup>6</sup>","= 300,000円 × 1.036544","= 310,963.2円"]},{type:"result",value:"▶ 答え 310,963円（円未満四捨五入）"}]},{answer:"1.51",questionTitle:"実利率",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"実利率とは、1年間に実際どれだけ増えるかを示す利率。名称利率が年率でも、年に複数回利息が付く場合は、その回数分だけ複利計算する。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["実利率 =（ 1 + 名称利率 ÷ 転化回数）<sup>転化回数</sup> - 1"]},{type:"note",value:"転化回数：1年間に利息を元金に繰り入れる回数"},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"① 1回あたりの利率"},{type:"formulaBlock",value:["= 0.015 ÷ 6","= 0.0025"]},{type:"text",value:"② 実利率"},{type:"formulaBlock",value:["= (1 + 0.0025)<sup>6</sup> − 1","= 1.015094 − 1","= 0.015094 = 1.5094％"]},{type:"result",value:"▶ 答え 1.51％（小数第3位を四捨五入）"}]},{answer:"1.53",questionTitle:"年平均利回り",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"まず、4年間の複利でどれだけ増えたか（総利回り）を求める。その後、それを4年で平均したものが年平均利回り。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["総利回り = (1 + 複利利率)<sup>期間</sup> − 1","年平均利回り = 総利回り ÷ 期間"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["複利利率：1.5％ = 0.015","投資期間：4年"]},{type:"text",value:"① 総利回り"},{type:"formulaBlock",value:["= (1 + 0.015)<sup>4</sup> − 1","= 1.061364 − 1","= 0.061364"]},{type:"text",value:"② 年平均利回り"},{type:"formulaBlock",value:["= 0.061364 ÷ 4","= 0.015341 = 1.5341％"]},{type:"result",value:"▶ 答え 1.53％（小数第3位を四捨五入）"}]},{answer:"1,956,950円",questionTitle:"必要資金（現在価値）",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"40万円を毎年始に5年間支払うために必要な資金は、各年の支払いを現在価値に割り引き、その合計で求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["現在価値 = 将来の金額 × (1 ÷ (1 + 利率))<sup>年数</sup>","必要資金 = 各年の現在価値の合計"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["毎年の支払額：400,000円（年始）","期間：5年間","年利率：1.1％ = 0.011"]},{type:"text",value:"① 各年の現在価値"},{type:"formulaBlock",value:["初年度（今年）：400,000円","1年後：400,000 × (1 ÷ 1.011) = 395,647.873…円 → 395,648円","2年後：400,000 × (1 ÷ 1.011)<sup>2</sup> = 391,343.099…円 → 391,343円","3年後：400,000 × (1 ÷ 1.011)<sup>3</sup> = 387,085.162…円 → 387,085円","4年後：400,000 × (1 ÷ 1.011)<sup>4</sup> = 382,873.553…円 → 382,874円"]},{type:"text",value:"② 合計"},{type:"formulaBlock",value:["現在において必要な資金の合計","= 400,000 + 395,648 + 391,343 + 387,085 + 382,874","= 1,956,950円"]},{type:"result",value:"▶ 答え 1,956,950円"}]}],labels:["カ","キ","ウ","エ","コ"]}),e(a,{questionNumber:6,title:t,subject:l,contents:[{answer:"0.98130",questionTitle:"生存率",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"生存率とは、「ある年齢の人が、次の年齢まで生き残る割合」のこと。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["生存率 = 期末の生存数 ÷ 期初の生存数"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["生存率（45歳 → 55歳）","= 55歳の生存数 ÷ 45歳の生存数","= 96,441 ÷ 98,279 = 0.981298…"]},{type:"result",value:"▶ 答え 0.98130（小数第6位を四捨五入）"}]},{answer:"97,957",questionTitle:"生存数",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"「5年後に何人残るか」は、今の人数に5年間生き残る割合（生存率）を掛けることで求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formula",value:"N年後の生存者数 = 基準年齢の人数 × 生存率"},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"5年後の生存者数"},{type:"formulaBlock",value:["基準年齢（60歳）の人数 × 生存率（60歳 → 65歳）","= 100,000 × 93,054 ÷ 94,995 = 97,956.7…"]},{type:"result",value:"▶ 答え 97,957（小数第1位を四捨五入）"}]},{answer:"1.02",questionTitle:"平均余命",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"平均余命とは、その年齢の全員がこれから生きる年数を全部足して、今の人数で割ったもの。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["延べ生存年数 = 死亡数 × 平均生存年数","平均余命 = 延べ生存年数の合計 ÷ 生存者数"]},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"① 各年齢の延べ生存年数"},{type:"note",value:"各年齢の死亡者は、その年齢内で平均<strong>0.5年</strong>生存したとみなして計算する。"},{type:"formulaBlock",value:["109歳：25.888 × 0.5 = 12.944 → 12.94","110歳：10.1008 × 1.5 = 15.1512 → 15.15","111歳：3.4515 × 2.5 = 8.62875 → 8.63","112歳：1.0162 × 3.5 = 3.5567 → 3.56","113歳：0.3155 × 4.5 = 1.41975 → 1.42"]},{type:"text",value:"② 109歳～113歳の延べ生存年数の合計"},{type:"note",value:"109歳以上の全員が、合計で何年分生きたかを合算する。"},{type:"formulaBlock",value:["12.94 + 15.15 + 8.63 + 3.56 + 1.42 = 41.70"]},{type:"text",value:"③ 109歳の平均余命"},{type:"formulaBlock",value:["109歳～113歳の延べ生存年数の合計 ÷ 109歳の生存者数","= 41.70 ÷ 40.772","= 1.02276…"]},{type:"result",value:"▶ 答え 1.02（小数第3位を四捨五入）"}]},{answer:"1,337,330",questionTitle:"保険金総額の現価",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"1年定期保険では、1年間に死亡した人に保険金を支払う。したがって、まず死亡者全員に支払う保険金の合計額を出し、支払い時点を年央（期央）とみなして、期央払現価率で割り引いて現価を求める。"},{type:"note",value:"※期央払現価率とは、年の真ん中で支払われると仮定したときの割引係数。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["合計保険金額 = 保険金 × 死亡数","現価 = 合計保険金額 × 期央払現価率（利率1.0%）"]},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"① 合計保険金額"},{type:"formulaBlock",value:["保険金（700万円） × 死亡数（50歳女性）","= 7,000千円 × 192人","= 1,344,000千円"]},{type:"text",value:"② 現価（年央払）"},{type:"formulaBlock",value:["合計保険金額 × 期央払現価率（利率1.0%）","= 1,344,000千円 × 0.995037","= 1,337,329.73千円"]},{type:"result",value:"▶ 答え：1,337,330千円（千円未満四捨五入）"}]},{answer:"13,710",questionTitle:"純保険料",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"純保険料は、必要な保険金総額の現価を、加入者全員で負担する額。したがって、必要な現価を年始生存者数で割る。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["純保険料 = 必要な現価 ÷ 年始生存者数"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["純保険料","= 必要な現価（問４の解） ÷ 50歳の年始生存者数","= 1,337,330千円 ÷ 97,539人","= 13,710.7208円"]},{type:"result",value:"▶ 答え 13,710円（10円未満四捨五入）"}]}],labels:["イ","ク","ウ","コ","カ"]}),e(o,{questionNumber:3,title:t,subject:l,questionTitle:"事業年度末責任準備金",contents:["未経過保険料","危険準備金","4月1日から翌年3月31日","契約月","保険リスク"],labels:["キ","イ","エ","ケ","コ"]}),e(o,{questionNumber:4,title:t,subject:l,questionTitle:"変額保険と定額保険の比較",contents:["保証はない","変動保険金額","毎日","契約者","生命保険会社"],labels:["コ","カ","キ","ケ","イ"]}),e(a,{questionNumber:21,title:t,subject:l,contents:[{answer:"3,209,282千円",questionTitle:"死亡保険金の現価",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"保険期間（50〜54歳）の各年齢で死亡した場合、死亡保険金が支払われる。支払いは年央（期央）と仮定されるため、各年齢の「死亡保険金 × 死亡数」を期央払現価率で割り引き、現価を合計する。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["各年齢の死亡保険金現価 = 死亡保険金 × 死亡数 × 期央払現価率","死亡保険金現価の合計 = 各年齢の死亡保険金現価の合計"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["死亡保険金：300万円 = 3,000千円","保険期間：5年（50〜54歳）","支払い：年央（期央）と仮定"]},{type:"text",value:"① 各年齢の死亡保険金現価"},{type:"formulaBlock",value:["50歳：3,000千円 × 192 × 0.995037 = 573,141千円","51歳：3,000千円 × 205 × 0.985185 = 605,889千円","52歳：3,000千円 × 219 × 0.975431 = 640,858千円","53歳：3,000千円 × 234 × 0.965773 = 677,973千円","54歳：3,000千円 × 248 × 0.956211 = 711,421千円"]},{type:"text",value:"② 合計"},{type:"formulaBlock",value:["死亡保険金現価の合計","= 573,141 + 605,889 + 640,858 + 677,973 + 711,421","= 3,209,282千円"]},{type:"result",value:"▶ 答え 3,209,282千円"}]},{answer:"275,280,998千円",questionTitle:"満期保険金の現価",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"満期保険金は、保険期間満了時（5年後）に生存している人に支払われる。したがって、まず 5年後の生存者数 × 保険金額 で将来の支払総額を求め、それを 期末払現価率 で割り引いて現価を求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["満期保険金の現価 = 5年後の生存者数 × 保険金額 × 期末払現価率（5年）"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["保険金額：300万円 = 3,000千円","5年後（55歳）の生存数：96,441人","5年の期末払現価率：0.951466"]},{type:"formulaBlock",value:["満期保険金の現価","= 96,441 × 3,000 × 0.951466","= 275,280,997.518千円"]},{type:"result",value:"▶ 答え 275,280,998千円（千円未満四捨五入）"}]},{answer:"7,315,425千円",questionTitle:"予定事業費の現価",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"予定事業費が「保険金1000円につき25円」と与えられているので、まず 1人あたりの予定事業費を求める。その後、加入時（50歳）の生存者数を掛けて、全体の予定事業費（現価）を求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["1人あたりの予定事業費 = 保険金額 ×（25 ÷ 1000）","予定事業費の現価（合計） = 1人あたりの予定事業費 × 加入時の生存者数"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["保険金額：300万円 = 3,000千円","予定事業費：保険金1000円につき25円 = 25 ÷ 1000","50歳の生存数：97,539人"]},{type:"text",value:"① 1人あたりの予定事業費"},{type:"formulaBlock",value:["= 3,000千円 ×（25 ÷ 1000）","= 3,000 × 0.025","= 75千円"]},{type:"text",value:"② 予定事業費の現価（合計）"},{type:"formulaBlock",value:["= 75千円 × 97,539人","= 7,315,425千円"]},{type:"result",value:"▶ 答え 7,315,425千円（千円未満四捨五入）"}]},{answer:"600,260円",questionTitle:"養老保険の年払営業保険料",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"年払営業保険料 P は、収支相当の原則（収入現価=支出現価）で求める。"},{type:"text",value:"収入現価：各年齢で生存している人が払う保険料 P を、期始払として現価に直して合計する"},{type:"text",value:"支出現価：死亡保険金・満期保険金・予定事業費の現価を合計する（問21〜23の結果）"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["収支相当の原則：収入現価 = 支出現価","各年齢の収入現価（期始払） = 生存数 × P × 期始払現価率","支出現価 = 死亡保険金現価 + 満期保険金現価 + 予定事業費現価"]},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"① 収入現価（50〜54歳、期始払）"},{type:"formulaBlock",value:["50歳：P × 97,539 × 1.000000 = 97,539P","51歳：P × 97,347 × 0.990099 = 96,383P","52歳：P × 97,141 × 0.980296 = 95,227P","53歳：P × 96,923 × 0.970590 = 94,072P","54歳：P × 96,689 × 0.960980 = 92,916P"]},{type:"formulaBlock",value:["収入現価の合計","= 97,539P + 96,383P + 95,227P + 94,072P + 92,916P","= 476,137P"]},{type:"text",value:"② 支出現価（問21〜23より）"},{type:"formulaBlock",value:["死亡保険金の現価（問21）= 3,209,282千円","満期保険金の現価（問22）= 275,280,998千円","予定事業費の現価（問23）= 7,315,425千円"]},{type:"formulaBlock",value:["支出現価","= 3,209,282 + 275,280,998 + 7,315,425","= 285,805,705千円 = 285,805,705,000円"]},{type:"text",value:"③ 収支相当の原則より P を求める"},{type:"formulaBlock",value:["収入現価 = 支出現価 より","476,137P = 285,805,705,000円","P = 285,805,705,000円 ÷ 476,137","P = 600,259…円"]},{type:"result",value:"▶ 答え 600,260円（10円未満四捨五入）"}]},{answer:"1,097,000円",questionTitle:"払済保険金額",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"払済保険とは、解約返戻金をもとに、同条件の養老保険を一時払で買い直すものである。したがって、解約返戻金で購入できる保険金額を比例計算で求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["払済保険金 = 解約返戻金 ×（保険金額 ÷ 一時払保険料）"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["解約返戻金：858,000円","保険金額：3,000,000円","一時払保険料：2,345,580円"]},{type:"formulaBlock",value:["払済保険金","= 858,000 ×（3,000,000 ÷ 2,345,580）","= 858,000 × 1.279…","= 1,097,383円"]},{type:"result",value:"▶ 答え 1,097,000円（千円未満四捨五入）"}]}],labels:["ア","イ","ウ","イ","ア"]}),e(u,{questionNumber:26,title:t,subject:l,questionTitle:"営業保険料",contents:["正しい","大きい契約ほど割合が高く、小さい契約ほど割合が低い → 大きい契約ほど割合が低く、小さい契約ほど割合が高い","正しい"]}),e(u,{questionNumber:27,title:t,subject:l,questionTitle:"チルメル式保険料積立金",contents:["危険保険料払込 → 貯蓄保険料","正しい","正しい"]}),e(u,{questionNumber:28,title:t,subject:l,questionTitle:"責任準備金の積立に関する法的規制",contents:["正しい","正しい","株主総会または総代会 → 取締役会"]}),e(u,{questionNumber:29,title:t,subject:l,questionTitle:"剰余金の発生源",contents:["経過年数が短いと死差益が少なく、経過年数が増すと死差益が多い → 経過年数が短いと死差益が多く、経過年数が増すと死差益が少ない","正しい","正しい"]}),e(u,{questionNumber:30,title:t,subject:l,questionTitle:"団体定期保険の数理",contents:["正しい","正しい","通常保険料 → 事情に応じて特別保険料、臨時保険料、剰余金等"]}),e(n,{questionNumber:31,title:t,subject:l,items:[{questionTitle:"平均余命",content:"ある年齢の人の平均寿命 → ある年齢の人の平均余命<br>0歳の平均寿命は平均余命 → 0歳の平均余命は平均寿命"},{questionTitle:"終価",content:"正しい"},{questionTitle:"予定利率",content:"保険金額 → 商品の特性"},{questionTitle:"分割払営業保険料",content:"年間払込額を上回る → 下回る"},{questionTitle:"責任準備金積立根拠",content:"平準保険料方式と同様 → 平準保険料方式と異なり"},{questionTitle:"責任準備金",content:"正しい"},{questionTitle:"延長保険",content:"死亡保険金額は少なくなる → 元契約と同額<br>保険期間は変わらない → 短縮される"},{questionTitle:"剰余金処分",content:"株式会社は、契約者配当財源を繰越利益剰余金から繰り入れるのではなく、契約者配当準備金繰入額として先取りし、当期純利益を算出する"},{questionTitle:"配当金支払方法",content:"支払いの対象とならない → 支払い対象"},{questionTitle:"特別勘定の位置付け",content:"正しい"},{questionTitle:"死亡率",label:"オ",content:""},{questionTitle:"死亡表の種類",label:"ウ",content:"総合表"},{questionTitle:"資産の平均利回り",label:"エ",content:"1年間の毎日の資産残高の累計"},{questionTitle:"純保険料の変化",label:"イ",content:"高くなる"},{questionTitle:"純保険料の分解",label:"ウ",content:"危険保険金"},{questionTitle:"解約返戻金の算式",label:"ア",content:"契約者貸付"},{questionTitle:"配当金の計算方法",label:"ア",content:"保険年度末保険料積立金"},{questionTitle:"契約転換制度",label:"イ",content:"責任準備金"},{questionTitle:"配当割当方法",label:"オ",content:""},{questionTitle:"団体定期保険の保険料",label:"ウ",content:"純保険料率"}]})]),e(s,{"previous-route":"keiri2021a","next-route":"keiri2021c"})])]),_:1}))}};export{w as default};
